'use strict';

const vq=require('./vq.js');
const https=require('https');

module.exports=function(q,tl='zh-CN'){
  return new Promise((resolve,reject)=>{
    if(typeof q!=='string' || q.trim().length===0) resolve('null');
    let tk=vq(q);
    q='&q='+encodeURIComponent(q);
    let url='https://translate.google.cn/translate_a/single?client=t&sl=auto&tl='+tl+'&hl=zh-CNdt=at&dt=bd&dt=ex&dt=ld&dt=md&dt=qca&dt=rw&dt=rm&dt=ss&dt=t&ie=UTF-8&oe=UTF-8&otf=2&ssel=0&tsel=0&kc=1'+tk+q;
    https.get(url, res=>{
      if(res.statusCode!==200) resolve('null');
      res.setEncoding('utf8');
      res.on('data', d=>resolve(d));
    }).on('error', resolve);
  });
};
